  1	import React, { FC, useCallback } from 'react';
  2	import classnames from 'classnames';
  3	
  4	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
  5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import { CloudInitDescription } from '@kubevirt-utils/components/CloudinitDescription/CloudInitDescription';
  7	import CloudinitModal from '@kubevirt-utils/components/CloudinitModal/CloudinitModal';
  8	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  9	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 10	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 11	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 12	import {
 13	  getTemplateVirtualMachineObject,
 14	  replaceTemplateVM,
 15	} from '@kubevirt-utils/resources/template';
 16	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 17	import {
 18	  Button,
 19	  DescriptionList,
 20	  Divider,
 21	  Flex,
 22	  FlexItem,
 23	  PageSection,
 24	  PageSectionVariants,
 25	  Title,
 26	} from '@patternfly/react-core';
 27	import { PencilAltIcon } from '@patternfly/react-icons';
 28	
 29	import useEditTemplateAccessReview from '../../hooks/useIsTemplateEditable';
 30	
 31	import SSHKey from './components/SSHKey/SSHKey';
 32	import SysPrepItem from './components/SysPrepItem/SysPrepItem';
 33	
 34	import './template-scripts-tab.scss';
 35	
 36	type TemplateScriptsPageProps = {
 37	  obj: V1Template;
 38	};
 39	
 40	const TemplateScriptsPage: FC<TemplateScriptsPageProps> = ({ obj: template }) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 43	  const vm = getTemplateVirtualMachineObject(template);
 44	
 45	  const { createModal } = useModal();
 46	
 47	  const onSubmitTemplate = useCallback(
 48	    (updatedTemplate: V1Template) =>
 49	      k8sUpdate({
 50	        data: updatedTemplate,
 51	        model: TemplateModel,
 52	        name: updatedTemplate?.metadata?.name,
 53	        ns: updatedTemplate?.metadata?.namespace,
 54	      }),
 55	    [],
 56	  );
 57	
 58	  const onUpdate = useCallback(
 59	    async (updatedVM: V1VirtualMachine) => {
 60	      await onSubmitTemplate(replaceTemplateVM(template, updatedVM));
 61	    },
 62	    [onSubmitTemplate, template],
 63	  );
 64	
 65	  return (
 66	    <PageSection variant={PageSectionVariants.light}>
 67	      <SidebarEditor<V1Template> onResourceUpdate={onSubmitTemplate} resource={template}>
 68	        <DescriptionList
 69	          className={classnames(
 70	            'pf-v6-c-description-list',
 71	            'template-scripts-tab__description-list',
 72	          )}
 73	        >
 74	          <VirtualMachineDescriptionItem
 75	            descriptionHeader={
 76	              <Flex className="vm-description-item__title">
 77	                <FlexItem>
 78	                  <Title headingLevel="h2">{t('Cloud-init')}</Title>
 79	                </FlexItem>
 80	                <FlexItem>
 81	                  <Button
 82	                    onClick={() =>
 83	                      createModal(({ isOpen, onClose }) => (
 84	                        <CloudinitModal
 85	                          isOpen={isOpen}
 86	                          onClose={onClose}
 87	                          onSubmit={onUpdate}
 88	                          vm={vm}
 89	                        />
 90	                      ))
 91	                    }
 92	                    isDisabled={!isTemplateEditable}
 93	                    isInline
 94	                    type="button"
 95	                    variant="link"
 96	                  >
 97	                    {t('Edit')}
 98	                    <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
 99	                  </Button>
100	                </FlexItem>
101	              </Flex>
102	            }
103	            descriptionData={<CloudInitDescription vm={vm} />}
104	          />
105	          <Divider />
106	          <SSHKey template={template} />
107	          <Divider />
108	          <SysPrepItem template={template} />
109	        </DescriptionList>
110	      </SidebarEditor>
111	    </PageSection>
112	  );
113	};
114	
115	export default TemplateScriptsPage;

